module dram_cell (
    input wire d,
    input wire we,
    input wire clk,
    output reg q
);
    reg unused_stored_bit;

    always @(posedge clk) begin
        if (we) begin
            unused_stored_bit <= d;
        end
    end

    always @* begin
        q = unused_stored_bit;
    end
endmodule
